sql:
SELECT candidate_id
FROM scrutiny_tasks
WHERE status = 'Pending';

SELECT COUNT(candidate_id) AS candidate_count
FROM candidate_examinations
WHERE examination_id = 1;

SELECT candidate_id, name, status
FROM candidates
ORDER BY name, status;

external_knowledge:
- Examination 0 refers to a specific examination with the ID 0; 
- 'Rejected' status means the candidate's application was not accepted; 
- 'Invalid Documents' is a reason for rejection, implying the candidate's documents were not in order.

